import axios, { AxiosError, AxiosRequestConfig } from "axios";
import { Analysis, AuthResponse, Resume, Session, User } from "./types";

const api = axios.create({
  baseURL: "/api",
  timeout: 30000
});

const authHeaders = (session: Session | null): AxiosRequestConfig["headers"] => {
  if (!session) {
    return {};
  }

  if (session.token) {
    return { Authorization: `Bearer ${session.token}` };
  }

  const password = session.password || session.user.username;
  return {
    Authorization: `Basic ${window.btoa(`${session.user.username}:${password}`)}`
  };
};

export const getErrorMessage = (error: unknown): string => {
  if (axios.isAxiosError(error)) {
    const axiosError = error as AxiosError<string | { error?: string; message?: string }>;
    const data = axiosError.response?.data;

    if (typeof data === "string" && data.trim()) {
      return data;
    }

    if (data && typeof data === "object") {
      return data.error || data.message || axiosError.message;
    }

    return axiosError.message;
  }

  return error instanceof Error ? error.message : "Something went wrong";
};

export const healthCheck = async (): Promise<string> => {
  const response = await api.get<{ status: string }>("/health");
  return response.data.status;
};

export const registerUser = async (
  username: string,
  email: string,
  password: string
): Promise<User> => {
  const response = await api.post<User>("/auth/register", {
    username,
    email,
    password
  });
  return response.data;
};

export const loginUser = async (
  username: string,
  password: string
): Promise<AuthResponse> => {
  const response = await api.post<AuthResponse>("/auth/login", {
    username,
    password
  });
  return response.data;
};

export const uploadResume = async (
  file: File,
  session: Session | null
): Promise<Resume> => {
  const formData = new FormData();
  formData.append("file", file);

  if (session?.user.id) {
    formData.append("userId", String(session.user.id));
  }

  const response = await api.post<Resume>("/upload/resume", formData, {
    headers: {
      ...authHeaders(session)
    }
  });
  return response.data;
};

export const createAnalysis = async (
  analysis: Required<Pick<Analysis, "resumeId" | "skills" | "experience" | "education" | "score" | "recommendations">>,
  session: Session | null
): Promise<Analysis> => {
  const response = await api.post<Analysis>("/analysis", analysis, {
    headers: authHeaders(session)
  });
  return response.data;
};

export const getAnalysis = async (
  resumeId: number,
  session: Session | null
): Promise<Analysis> => {
  const response = await api.get<Analysis>(`/analysis/${resumeId}`, {
    headers: authHeaders(session)
  });
  return response.data;
};

export const getAnalysesForResume = async (
  resumeId: number,
  session: Session | null
): Promise<Analysis[]> => {
  const response = await api.get<Analysis[]>(`/analysis/resume/${resumeId}`, {
    headers: authHeaders(session)
  });
  return response.data;
};
